def _get_feedback_email() -> str:
    """Resolve feedback email: secrets → env → SMTP_USER → hardcoded default."""
    try:
        v = st.secrets.get("FEEDBACK_EMAIL", "")
        if v: return v
    except Exception:
        pass
    _env = os.environ.get("FEEDBACK_EMAIL", "")
    if _env: return _env
    try:
        v2 = st.secrets.get("SMTP_USER", "")
        if v2: return v2
    except Exception:
        pass
    _env2 = os.environ.get("SMTP_USER", "")
    if _env2: return _env2
    # Final fallback — always show a valid contact even if nothing is configured
    return "mansagold12@gmail.com"
_FEEDBACK_EMAIL = _get_feedback_email()

