# ═══════════════════════════════════════════════════════════════════════════════
# SUPABASE PERSISTENCE LAYER
# ───────────────────────────────────────────────────────────────────────────────
# Set these in .streamlit/secrets.toml to enable cross-session persistence:
#
#   [secrets]
#   SUPABASE_URL  = "https://xxxx.supabase.co"
#   SUPABASE_KEY  = "eyJ..."   # anon/public key
#
# Required Supabase table (run once in the SQL Editor):
#
#   create table if not exists mansa_user_data (
#     user_id      text primary key,
#     portfolio    jsonb default '[]'::jsonb,
#     alerts       jsonb default '[]'::jsonb,
#     journal      jsonb default '[]'::jsonb,
#     profile      jsonb default '{}'::jsonb,
#     updated_at   timestamptz default now()
#   );
#   alter table mansa_user_data enable row level security;
#   create policy "Users can manage own data"
#     on mansa_user_data for all
#     using  (user_id = current_user)
#     with check (user_id = current_user);
#
# Without Supabase credentials everything works exactly as before — all data
# lives in session_state only (lost on browser close).
# ═══════════════════════════════════════════════════════════════════════════════

def _get_sb_config() -> tuple:
    """Return (supabase_url, supabase_key). Tries multiple sources in order:
       1. .streamlit/secrets.toml (preferred for production)
       2. Environment variables
       3. Hardcoded values at top of this file (for local dev)
       4. Backup config in user's home directory: ~/.mansa_supabase.toml
    """
    # 1. Try Streamlit secrets.toml — handles BOTH key naming conventions
    for url_key, key_key in [("SUPABASE_URL", "SUPABASE_KEY"),
                              ("supabase_url", "supabase_key")]:
        try:
            if url_key in st.secrets and key_key in st.secrets:
                u = st.secrets[url_key]
                k = st.secrets[key_key]
                if u and k:
                    return str(u).strip(), str(k).strip()
        except Exception:
            pass

    # 2. Environment variables
    u = os.environ.get("SUPABASE_URL", "").strip()
    k = os.environ.get("SUPABASE_KEY", "").strip()
    if u and k:
        return u, k

    # 3. Hardcoded values at top of file
    if _HARDCODED_SUPABASE_URL and _HARDCODED_SUPABASE_KEY:
        return _HARDCODED_SUPABASE_URL.strip(), _HARDCODED_SUPABASE_KEY.strip()

    # 4. Backup: try a file in user home directory ~/.mansa_supabase.toml
    try:
        import pathlib
        home_cfg = pathlib.Path.home() / ".mansa_supabase.toml"
        if home_cfg.exists():
            content = home_cfg.read_text(encoding="utf-8")
            url_match = re.search(r'SUPABASE_URL\s*=\s*"([^"]+)"', content)
            key_match = re.search(r'SUPABASE_KEY\s*=\s*"([^"]+)"', content)
            if url_match and key_match:
                u = url_match.group(1).strip()
                k = key_match.group(1).strip()
                if u and k:
                    return u, k
    except Exception:
        pass

    return (None, None)


