# ── 11: Service Worker — offline cache ───────────────────────────────────────
st.components.v1.html(
    """<script>
(function(){
  if(!('serviceWorker' in navigator))return;
  var code=[
    "const C='mansa-v1';",
    "self.addEventListener('install',function(e){",
    "  self.skipWaiting();",
    "  e.waitUntil(caches.open(C).then(function(c){return c.addAll(['/']);}));",
    "});",
    "self.addEventListener('activate',function(e){",
    "  e.waitUntil(caches.keys().then(function(keys){",
    "    return Promise.all(keys.filter(function(k){return k!==C;}).map(function(k){return caches.delete(k);}));",
    "  }));",
    "  self.clients.claim();",
    "});",
    "self.addEventListener('fetch',function(e){",
    "  if(e.request.method!=='GET')return;",
    "  e.respondWith(fetch(e.request).catch(function(){return caches.match(e.request);}));",
    "});"
  ].join('\n');
  try{
    var blob=new Blob([code],{type:'application/javascript'});
    var url=URL.createObjectURL(blob);
    navigator.serviceWorker.register(url,{scope:'/'}).then(function(){
      URL.revokeObjectURL(url);
    }).catch(function(){});
  }catch(err){}
})();
</script>""",
    height=0, scrolling=False
)


