def _on_theme_change():
    """Sync widget value → main state. Streamlit auto-reruns after callback."""
    _v = st.session_state.get("mode_theme_picker")
    if _v and _v in THEMES:
        st.session_state["theme"] = _v
        try: _sb_save()
        except Exception: pass


def _on_lang_change():
    """Sync widget value → main state. Streamlit auto-reruns after callback."""
    _v = st.session_state.get("mode_lang_picker")
    if _v and _v in LANGS:
        # Translate nav state: find which nav_key matches the current nav value
        # in the OLD language, then update nav to that same key's value in the NEW language
        _old_lang = st.session_state.get("lang", "")
        _cur_nav  = st.session_state.get("nav", "")
        if _old_lang in LANGS and _cur_nav:
            _old_L = LANGS[_old_lang]
            _new_L = LANGS[_v]
            # Find the nav_key whose value matches current nav
            for _k, _val in _old_L.items():
                if _k.startswith("nav_") and _val == _cur_nav:
                    if _k in _new_L:
                        st.session_state["nav"] = _new_L[_k]
                    break
        st.session_state["lang"] = _v
        try: _sb_save()
        except Exception: pass


def _render_mode_toggle():
    """Inline mode toggle: light/dark + theme + language pickers.

    Pattern: single source of truth (st.session_state['theme'] / ['lang']).
    Widget keys initialized ONCE only — never overwritten on subsequent runs.
    """
    st.markdown("<div class='mansa-mode-toggle'>", unsafe_allow_html=True)
    _mc = st.columns([4, 4])

    with _mc[0]:
        _theme_keys = list(THEMES.keys())
        # Make sure main state is valid
        if st.session_state.get("theme") not in _theme_keys:
            st.session_state["theme"] = _theme_keys[0]
        # Re-sync widget state if it points to a deleted theme
        if "mode_theme_picker" not in st.session_state or \
           st.session_state.get("mode_theme_picker") not in _theme_keys:
            st.session_state["mode_theme_picker"] = st.session_state["theme"]
        st.selectbox(
            "theme",
            _theme_keys,
            key="mode_theme_picker",
            label_visibility="collapsed",
            on_change=_on_theme_change,
            format_func=lambda k: THEMES[k].get("brand","") + " " + (
                THEMES[k].get("desc", k[:12]) if is_rtl()
                else THEMES[k].get("desc_en", THEMES[k].get("desc", k[:12]))
            ),
        )

    with _mc[1]:
        _lang_keys = list(LANGS.keys())
        if st.session_state.get("lang") not in _lang_keys:
            st.session_state["lang"] = _lang_keys[0]
        # Re-sync widget state if it points to a deleted language
        if "mode_lang_picker" not in st.session_state or \
           st.session_state.get("mode_lang_picker") not in _lang_keys:
            st.session_state["mode_lang_picker"] = st.session_state["lang"]
        st.selectbox(
            "lang",
            _lang_keys,
            key="mode_lang_picker",
            label_visibility="collapsed",
            on_change=_on_lang_change,
            format_func=lambda x: x.rsplit(" ", 1)[0],
        )

    st.markdown("</div>", unsafe_allow_html=True)


