# 📜 NAV HISTORY — back/forward/reload buttons like a browser
# ═══════════════════════════════════════════════════════════════════════════════
def _nav_history_push(page: str) -> None:
    """Add a page to navigation history (only if different from last)."""
    if "_nav_back_stack" not in st.session_state:
        st.session_state["_nav_back_stack"] = []
    if "_nav_fwd_stack" not in st.session_state:
        st.session_state["_nav_fwd_stack"] = []
    _stack = st.session_state["_nav_back_stack"]
    # Don't push if same as current top
    if not _stack or _stack[-1] != page:
        _stack.append(page)
        # Keep history bounded
        if len(_stack) > 50:
            _stack.pop(0)
        st.session_state["_nav_back_stack"] = _stack
        # Pushing a new page clears the forward stack (like a browser)
        st.session_state["_nav_fwd_stack"] = []


def _nav_can_go_back() -> bool:
    return len(st.session_state.get("_nav_back_stack", [])) > 1


def _nav_can_go_forward() -> bool:
    return len(st.session_state.get("_nav_fwd_stack", [])) > 0


def _nav_go_back() -> None:
    _stack = st.session_state.get("_nav_back_stack", [])
    if len(_stack) > 1:
        _current = _stack.pop()
        _fwd = st.session_state.get("_nav_fwd_stack", [])
        _fwd.append(_current)
        st.session_state["_nav_fwd_stack"] = _fwd
        st.session_state["_nav_back_stack"] = _stack
        st.session_state["_nav_skip_push"] = True   # so we don't re-push on rerun
        st.session_state["nav"] = _stack[-1]


def _nav_go_forward() -> None:
    _fwd = st.session_state.get("_nav_fwd_stack", [])
    if _fwd:
        _next = _fwd.pop()
        _back = st.session_state.get("_nav_back_stack", [])
        _back.append(_next)
        st.session_state["_nav_back_stack"] = _back
        st.session_state["_nav_fwd_stack"] = _fwd
        st.session_state["_nav_skip_push"] = True
        st.session_state["nav"] = _next


