def _render_top_bar():
    """Clean horizontal navigation: back/fwd/reload + 4 pills + More menu."""
    use_ar_tb = is_rtl()
    _render_mode_toggle()

    # ── Track navigation history (push current page) ──────────────────────────
    _current_nav = st.session_state.get("nav", L["nav_dashboard"])
    if not st.session_state.get("_nav_skip_push"):
        _nav_history_push(_current_nav)
    st.session_state["_nav_skip_push"] = False

    # ── Masthead (logo + brand) — larger sizing for better visibility ─────────
    _logo_html = get_logo_svg(st.session_state.get("theme", list(THEMES.keys())[0]), width=72)
    st.markdown(f"""
    <div style='display:flex;align-items:center;gap:20px;padding:18px 20px 14px;
                border-bottom:1px solid {C["border"]};margin-bottom:18px;'
         dir='{'rtl' if use_ar_tb else 'ltr'}'>
      <div style='flex-shrink:0;'>{_logo_html}</div>
      <div style='flex:1;'>
        <div style='font-family:{C["font_h"]},serif;font-size:32px;
                    color:{C["gold"]};font-weight:700;line-height:1.1;letter-spacing:.03em;'>
          {L['app_name']}
        </div>
        <div style='font-size:15px;color:{C["muted"]};letter-spacing:.14em;margin-top:4px;'>
          {L.get('daily_gold_report', 'Daily Gold Report')}
        </div>
      </div>
    </div>
    """, unsafe_allow_html=True)

    # ── Browser-like nav buttons: ◀ ▶ ⟳ ───────────────────────────────────────
    _can_back = _nav_can_go_back()
    _can_fwd  = _nav_can_go_forward()
    # In RTL: visual order is reversed — but Streamlit columns are LTR, so we
    # swap the symbols (and labels) to keep the experience consistent.
    _back_icon, _fwd_icon = ("→", "←") if use_ar_tb else ("←", "→")
    _back_help = L.get("nav_back", "Back")
    _fwd_help  = L.get("nav_forward", "Forward")
    _reload_help = L.get("nav_reload", "Reload")

    _nav_cols = st.columns([1, 1, 1, 8])
    with _nav_cols[0]:
        if st.button(_back_icon,
                     key="navbtn_back",
                     help=_back_help,
                     use_container_width=True,
                     disabled=not _can_back):
            _nav_go_back()
            st.rerun()
    with _nav_cols[1]:
        if st.button(_fwd_icon,
                     key="navbtn_fwd",
                     help=_fwd_help,
                     use_container_width=True,
                     disabled=not _can_fwd):
            _nav_go_forward()
            st.rerun()
    with _nav_cols[2]:
        if st.button("⟳",
                     key="navbtn_reload",
                     help=_reload_help,
                     use_container_width=True):
            st.rerun()

    # ── Pills row: Home + 3 persona-based + More button ───────────────────────
    _is_more_open = st.session_state.get("_more_menu_open", False)
    _pills = _get_quick_pills()

    _cols = st.columns(len(_pills) + 1)
    for _i, (_pkey, _icon, (_ar, _en)) in enumerate(_pills):
        # Use the actual translation from L (works for all 10 languages, not just ar/en)
        # The L[_pkey] already includes the emoji prefix; we just use it as-is.
        _full_label = L.get(_pkey, "")
        if _full_label:
            # Strip leading emoji + double-space (e.g. "🏠  الرئيسية" → "الرئيسية")
            # so we can prepend our pill icon consistently
            import re as _re_pill
            _label_text = _re_pill.sub(r"^[^\w]+\s+", "", _full_label).strip()
            if not _label_text:
                _label_text = _ar if use_ar_tb else _en
        else:
            _label_text = _ar if use_ar_tb else _en
        _target = L.get(_pkey, "")
        _is_active = (_current_nav == _target)
        with _cols[_i]:
            if st.button(f"{_icon}  {_label_text}",
                         key=f"pill_{_pkey}",
                         type=("primary" if _is_active else "secondary"),
                         use_container_width=True):
                st.session_state["nav"] = _target
                st.session_state["_more_menu_open"] = False
                st.rerun()

    # More button (last column)
    with _cols[-1]:
        _more_label = L.get("close_menu", "✕  Close") if _is_more_open \
                      else L.get("more_menu", "☰  More")
        if st.button(_more_label,
                     key="pill_more_btn",
                     type=("primary" if _is_more_open else "secondary"),
                     use_container_width=True):
            st.session_state["_more_menu_open"] = not _is_more_open
            st.rerun()

    # ── More menu drawer (expanded list of all remaining pages) ───────────────
    if _is_more_open:
        st.markdown(
            f"<div style='border:1px solid {C['gold']}44;border-radius:10px;"
            f"padding:18px 16px;margin:14px 0 6px;background:{C['bg2']}66;'>",
            unsafe_allow_html=True
        )
        # Search bar inside More menu
        _search_q = st.text_input(
            "",
            key="_more_search",
            placeholder=("🔍  ابحث في كل الصفحات..." if use_ar_tb
                          else "🔍  Search all pages..."),
            label_visibility="collapsed"
        )

        if _search_q and len(_search_q.strip()) >= 1:
            # Search mode: show matching pages across all groups
            _q = _search_q.strip().lower()
            _matches = []
            for _icon, _, _keys in _MORE_GROUPS:
                for _nk in _keys:
                    _lbl = L.get(_nk, "")
                    if _lbl and _q in _lbl.lower():
                        _matches.append((_icon, _nk, _lbl))
            if _matches:
                _cols_search = st.columns(3)
                for _i, (_icon, _nk, _lbl) in enumerate(_matches[:9]):
                    with _cols_search[_i % 3]:
                        if st.button(f"{_icon}  {_lbl}",
                                     key=f"more_search_{_nk}",
                                     use_container_width=True):
                            st.session_state["nav"] = _lbl
                            st.session_state["_more_menu_open"] = False
                            if "_more_search" in st.session_state:
                                del st.session_state["_more_search"]
                            st.rerun()
            else:
                st.markdown(
                    f"<div style='text-align:center;color:{C['muted']};"
                    f"padding:14px;font-size:15px;font-style:italic;'>"
                    f"🔍 {L.get('no_results', 'No results')}</div>",
                    unsafe_allow_html=True
                )
        else:
            # Normal mode: show grouped pages
            for _icon, (_g_ar, _g_en), _keys in _MORE_GROUPS:
                _g_label = _g_ar if use_ar_tb else _g_en
                # Section header
                st.markdown(
                    f"<div style='margin:14px 0 8px;font-size:13px;font-weight:700;"
                    f"color:{C['gold_pale']};letter-spacing:.08em;text-transform:uppercase;'>"
                    f"{_icon}  {_g_label}</div>",
                    unsafe_allow_html=True
                )
                # Pages in this group
                _avail = [(_nk, L.get(_nk, "")) for _nk in _keys if L.get(_nk, "")]
                if not _avail:
                    continue
                # Display in rows of 3
                for _row_start in range(0, len(_avail), 3):
                    _row = _avail[_row_start:_row_start + 3]
                    _row_cols = st.columns(3)
                    for _ci, (_nk, _lbl) in enumerate(_row):
                        _is_active_p = (_current_nav == _lbl)
                        with _row_cols[_ci]:
                            if st.button(_lbl,
                                         key=f"more_{_nk}",
                                         type=("primary" if _is_active_p else "secondary"),
                                         use_container_width=True):
                                st.session_state["nav"] = _lbl
                                st.session_state["_more_menu_open"] = False
                                st.rerun()

        st.markdown("</div>", unsafe_allow_html=True)


