        @st.cache_data(ttl=900, show_spinner=False)
        def fetch_geo_news_all(topics_json: str) -> dict:
            """Fetch news for all geo topics. Cached 15 min."""
            import json, requests as _rq, xml.etree.ElementTree as _ET
            topics = json.loads(topics_json)
            result = {}
            for t in topics:
                try:
                    _rss = f"https://news.google.com/rss/search?q={t['q']}&hl=en&gl=US&ceid=US:en"
                    _r   = _rq.get(_rss, timeout=7, headers={"User-Agent": "Mozilla/5.0"})
                    if _r.status_code != 200:
                        result[t["id"]] = []
                        continue
                    root  = _ET.fromstring(_r.content)
                    items = root.findall(".//item")[:4]
                    nl = []
                    for it in items:
                        title = (it.find("title").text or "").strip()
                        guid  = it.find("guid")
                        lkel  = it.find("link")
                        url   = (guid.text if guid is not None and guid.text and guid.text.startswith("http")
                                 else (lkel.text if lkel is not None and lkel.text else "#"))
                        pub   = (it.find("pubDate").text or "")[:16]
                        src   = ""
                        if " - " in title:
                            title, src = title.rsplit(" - ", 1)
                        nl.append({"title": title.strip(), "link": url.strip(), "pub": pub, "src": src.strip()})
                    result[t["id"]] = nl
                except Exception:
                    result[t["id"]] = []
            return result

